#include<bits/stdc++.h>
using namespace std;
vector<int> v;
int a[101],f[1000010],g[1000010];
int main()
{
    int n,w;
    scanf("%d%d",&n,&w);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    memset(f,0x3f,sizeof(f));
    f[0]=1;
    g[0]=0;
    for(int j=0;j<(1<<n);j++)
    {
        for(int i=1;i<=n;i++)
        {
            if(!(j&(1<<(i-1))))
            {
                int now=j|(1<<(i-1));
                if(g[j]+a[i]<=w)
                {
                    if(f[j]<f[now])
                    {
                        f[now]=f[j];
                        g[now]=g[j]+a[i];
                    }
                    else if(f[j]==f[now])
                    {
                        g[now]=min(g[j]+a[i],g[now]);
                    }
                }
                else
                {
                    if(f[j]+1<f[now])
                    {
                        f[now]=f[j]+1;
                        g[now]=a[i];
                    }
                    else if(f[j]+1==f[now])
                    {
                        g[now]=min(a[i],g[now]);
                    }
                }
            }
        }
    }
    printf("%d",f[(1<<n)-1]);
    return 0;
}
